<?php namespace App\Repositories\FrontOffice;use App\Repositories\BaseRepository;use App\Models\FrontOffice\Complaint;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class ComplaintRepository extends BaseRepository{    public function __construct(Complaint $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function findByType(string $type): Collection    {        return $this->findByField('complaint_type', $type);    }    public function findByPriority(string $priority): Collection    {        return $this->findByField('priority', $priority);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('complaint_date', [$startDate, $endDate])->get();    }    public function searchComplaints(string $keyword): Collection    {        return $this->query()->where('complainant_name', 'like', "%{$keyword}%")->orWhere('complainant_phone', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getPendingComplaints(): Collection    {        return $this->query()->where('status', 'pending')->orderBy('created_at', 'desc')->get();    }    public function getResolvedComplaints(): Collection    {        return $this->query()->where('status', 'resolved')->get();    }    public function getHighPriorityComplaints(): Collection    {        return $this->query()->where('priority', 'high')->where('status', '!=', 'resolved')->get();    }    public function assignTo(int $id, int $userId): bool    {        return $this->update($id, ['assigned_to' => $userId]);    }    public function resolveComplaint(int $id, string $resolution): bool    {        return $this->update($id, [            'status' => 'resolved',            'resolution' => $resolution,            'resolved_at' => now(),        ]);    }    public function reopenComplaint(int $id): bool    {        return $this->update($id, ['status' => 'reopened', 'resolved_at' => null]);    }    public function countByType(): Collection    {        return $this->query()->selectRaw('complaint_type, COUNT(*) as total')->groupBy('complaint_type')->get();    }}